            this.rect = new Rectangle(x, y, width, height);
        }

        @Override
        public boolean overlaps(Shape other) {
            if (other instanceof Rect) {
                return this.rect.overlaps(((Rect) other).rect);
            } else if (other instanceof Circ) {
                return Intersector.overlaps(((Circ) other).circle, this.rect);
            }
            return false;
        }
    }

    // -- Circle --------------------------------------------------------------

    public static final class Circ extends Shape {
        private final Circle circle;

        public Circ(String id, float x, float y, float radius) {
            super(id);
            this.circle = new Circle(x, y, radius);
        }

        @Override
        public boolean overlaps(Shape other) {
            if (other instanceof Circ) {
                return this.circle.overlaps(((Circ) other).circle);
            } else if (other instanceof Rect) {
                return Intersector.overlaps(this.circle, ((Rect) other).rect);
            }
            return false;
        }
    }
}

package com.gdxgame;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.Reader;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

/**
 * Parses the shape definition file into a list of {@link Shape} objects.
 *
 * <p>Validation rules:
 * <ul>
 *   <li>Lines starting with '#' are comments and are skipped.</li>
 *   <li>Blank/whitespace-only lines are skipped.</li>
 *   <li>IDs must be unique; duplicate IDs cause an error.</li>
 *   <li>width, height, and radius must be strictly positive.</li>
 *   <li>Malformed lines cause an error with the raw line printed verbatim.</li>
 * </ul>
 */
public class ShapeParser {

    private ShapeParser() {
        // utility class
    }

    /**
     * Parses shapes from the given reader. On success, returns the parsed list.
     * On any parse error, throws {@link ParseException} with a message suitable
     * for stderr output.
     */
    public static List<Shape> parse(Reader reader) throws IOException, ParseException {
        List<Shape> shapes = new ArrayList<>();
        Set<String> seenIds = new HashSet<>();

        try (BufferedReader br = new BufferedReader(reader)) {
            String line;
            int lineNumber = 0;
            while ((line = br.readLine()) != null) {
                lineNumber++;

                // Skip comments and blank lines
                String trimmed = line.trim();
                if (trimmed.isEmpty() || trimmed.startsWith("#")) {
                    continue;
                }

                String[] tokens = trimmed.split("\\s+");
                if (tokens.length < 2) {
                    throw new ParseException("Error: invalid shape line: " + line);
                }

                String id = tokens[0];
                String type = tokens[1];

                // Validate ID uniqueness
                if (!seenIds.add(id)) {
                    throw new ParseException("Error: duplicate id " + id);
                }

                Shape shape;
                switch (type) {
                    case "rect":
                        shape = parseRect(id, tokens, line);
                        break;
                    case "circle":
                        shape = parseCircle(id, tokens, line);
                        break;
                    default:
                        throw new ParseException("Error: invalid shape line: " + line);
                }

                shapes.add(shape);
            }
        }

        return shapes;
    }

    private static Shape parseRect(String id, String[] tokens, String rawLine) throws ParseException {
        // Expected: <id> rect <x> <y> <width> <height>  => 6 tokens
        if (tokens.length != 6) {
            throw new ParseException("Error: invalid shape line: " + rawLine);
        }
        try {
            float x = Float.parseFloat(tokens[2]);
            float y = Float.parseFloat(tokens[3]);
            float width = Float.parseFloat(tokens[4]);
            float height = Float.parseFloat(tokens[5]);

            if (width <= 0 || height <= 0) {
                throw new ParseException("Error: invalid shape line: " + rawLine);
            }

            return new Shape.Rect(id, x, y, width, height);
        } catch (NumberFormatException e) {
            throw new ParseException("Error: invalid shape line: " + rawLine);
        }
    }

    private static Shape parseCircle(String id, String[] tokens, String rawLine) throws ParseException {
        // Expected: <id> circle <x> <y> <radius>  => 5 tokens
        if (tokens.length != 5) {
            throw new ParseException("Error: invalid shape line: " + rawLine);
        }
        try {
            float x = Float.parseFloat(tokens[2]);
            float y = Float.parseFloat(tokens[3]);
            float radius = Float.parseFloat(tokens[4]);

            if (radius <= 0) {
                throw new ParseException("Error: invalid shape line: " + rawLine);
            }

            return new Shape.Circ(id, x, y, radius);
        } catch (NumberFormatException e) {
            throw new ParseException("Error: invalid shape line: " + rawLine);
        }
    }

    // -- Exception -----------------------------------------------------------

    public static final class ParseException extends Exception {
        public ParseException(String message) {
            super(message);
        }
    }
}

package com.gdxgame;

import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;

/**
 * Computes all overlapping pairs from a list of shapes using libGDX's
 * geometry primitives.
 */
public class OverlapDetector {

    private OverlapDetector() {
        // utility class
    }

    /**
     * Represents an unordered pair of overlapping shapes, identified by their IDs.
     */
    public static final class OverlapPair {
        public final String idA; // lexicographically smaller
        public final String idB; // lexicographically larger

        public OverlapPair(String idA, String idB) {
            if (idA.compareTo(idB) <= 0) {
                this.idA = idA;
                this.idB = idB;
            } else {
                this.idA = idB;
                this.idB = idA;
            }
        }
    }

    /**
     * Computes all distinct overlapping pairs from the given shape list.
     * Each unordered pair is reported at most once, with the lexicographically
     * smaller ID first.
     */
    public static List<OverlapPair> findOverlaps(List<Shape> shapes) {
        List<OverlapPair> pairs = new ArrayList<>();

        for (int i = 0; i < shapes.size(); i++) {
            Shape a = shapes.get(i);
            for (int j = i + 1; j < shapes.size(); j++) {
                Shape b = shapes.get(j);
                if (a.overlaps(b)) {
                    pairs.add(new OverlapPair(a.getId(), b.getId()));
                }
            }
        }

        // Sort: primary key idA, secondary key idB
        Collections.sort(pairs, Comparator.comparing((OverlapPair p) -> p.idA)
                .thenComparing(p -> p.idB));

        return pairs;
    }
}

package com.gdxgame;

import java.io.BufferedWriter;
import java.io.IOException;
import java.io.Writer;
import java.util.List;

/**
 * Writes the sorted collision report to an output writer.
 */
public class OutputWriter {

    private OutputWriter() {
        // utility class
    }

    /**
     * Writes the collision report. Format:
     * <pre>
     * id_a\tid_b
     * id_a\tid_b
     * ...
     * total_overlaps=N
     * </pre>
     * Trailing newline is included.
     */
    public static void write(Writer writer, List<OverlapDetector.OverlapPair> pairs) throws IOException {
        try (BufferedWriter bw = new BufferedWriter(writer)) {
            for (OverlapDetector.OverlapPair pair : pairs) {
                bw.write(pair.idA);
                bw.write('\t');
                bw.write(pair.idB);
                bw.newLine();
            }
            bw.write("total_overlaps=" + pairs.size());
            bw.newLine();
        }
    }
}

