import java.io.*;
import java.util.List;

/**
 * libGDX ApplicationListener that runs on the headless backend.
 * On the first render tick it loads the shape file, computes overlaps,
 * writes the report, and exits.
 */
public class HeadlessAppListener extends ApplicationAdapter {

    private final String inputPath;
    private final String outputPath;
    private boolean done = false;

    public HeadlessAppListener(String inputPath, String outputPath) {
        this.inputPath = inputPath;
        this.outputPath = outputPath;
    }

    @Override
    public void create() {
        // Defer work to render() so HeadlessApplication is fully initialized.
    }

    @Override
    public void render() {
        if (done) {
            return;
        }
        done = true;

        try {
            // Parse input
            FileHandle inputFile = Gdx.files.absolute(inputPath);
            if (!inputFile.exists()) {
                System.err.println("Error: input file not found: " + inputPath);
                System.exit(1);
                return;
            }

            List<Shape> shapes;
            try (Reader reader = inputFile.reader("UTF-8")) {
                shapes = ShapeParser.parse(reader);
            }

            // Compute overlaps
            List<OverlapDetector.OverlapPair> pairs = OverlapDetector.findOverlaps(shapes);

            // Write output
            FileHandle outputFile = Gdx.files.absolute(outputPath);
            try (Writer writer = outputFile.writer(false, "UTF-8")) {
                OutputWriter.write(writer, pairs);
            }

            // Success
            Gdx.app.exit();
        } catch (ShapeParser.ParseException e) {
            System.err.println(e.getMessage());
            System.exit(1);
        } catch (IOException e) {
            System.err.println("Error: I/O error: " + e.getMessage());
            System.exit(1);
        }
    }
}

package com.gdxgame;

import com.badlogic.gdx.backends.headless.HeadlessApplication;
import com.badlogic.gdx.backends.headless.HeadlessApplicationConfiguration;

/**
 * Entry point. Parses --shapes=<path> and --output=<path> arguments,
 * boots a HeadlessApplication with our listener, and waits for it to finish.
 */
public class Main {

    public static void main(String[] args) {
        String inputPath = null;
        String outputPath = null;

        for (String arg : args) {
            if (arg.startsWith("--shapes=")) {
                inputPath = arg.substring("--shapes=".length());
            } else if (arg.startsWith("--output=")) {
                outputPath = arg.substring("--output=".length());
            }
        }

        if (inputPath == null || outputPath == null) {
            System.err.println("Usage: gdx-game --shapes=<input_path> --output=<output_path>");
            System.exit(1);
            return;
        }

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        config.updatesPerSecond = 0; // don't busy-wait

        HeadlessApplication app = new HeadlessApplication(
                new HeadlessAppListener(inputPath, outputPath),
                config
        );

        // Wait for the headless main loop to finish (listener calls Gdx.app.exit())
        try {
            app.getMainLoopThread().join();
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
            System.err.println("Error: interrupted while waiting for completion");
            System.exit(1);
        }
    }
}

